import{c as a,Q as r,j as e,m as o}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"RWKV 模型架构简介","description":"","frontmatter":{},"headers":[],"relativePath":"杂项/RWKV模型架构简介.md","filePath":"杂项/RWKV模型架构简介.md","lastUpdated":1782819565000}'),n={name:"杂项/RWKV模型架构简介.md"};function l(i,t,s,h,d,c){return r(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="rwkv-模型架构简介" tabindex="-1">RWKV 模型架构简介 <a class="header-anchor" href="#rwkv-模型架构简介" aria-label="Permalink to &quot;RWKV 模型架构简介&quot;">​</a></h1><blockquote><p>RWKV 是一条和 Transformer 不同的大语言模型路线。它试图把 Transformer 的并行训练能力和 RNN 的常量状态推理能力结合起来:训练时像 Transformer 一样高效并行,推理时像 RNN 一样只维护固定大小的状态。</p></blockquote><hr><h2 id="一句话结论" tabindex="-1">一句话结论 <a class="header-anchor" href="#一句话结论" aria-label="Permalink to &quot;一句话结论&quot;">​</a></h2><p>RWKV 可以理解为一种「<strong>Transformer 能力取向 + RNN 推理形态</strong>」的语言模型架构。它的最大特点不是在所有任务上压过 Transformer,而是用固定大小的 recurrent state 替代不断增长的 KV Cache,因此在长文本推理、低显存部署、边缘设备运行上有独特吸引力。</p><hr><h2 id="一、为什么会有-rwkv" tabindex="-1">一、为什么会有 RWKV <a class="header-anchor" href="#一、为什么会有-rwkv" aria-label="Permalink to &quot;一、为什么会有 RWKV&quot;">​</a></h2><p>主流大语言模型大多基于 Transformer。Transformer 的核心是 Self-Attention,它非常适合并行训练,也很擅长在上下文里建立 token 之间的关系。但它有一个工程代价:自回归生成时需要保存历史 token 的 Key / Value,也就是 <strong>KV Cache</strong>。</p><p>上下文越长,KV Cache 越大。对服务端推理来说,这会带来显存压力;对本地和边缘设备来说,这会直接限制可用上下文长度和并发能力。</p><p>RWKV 的出发点就是:能不能保留类似 Transformer 的表达能力,但推理时不再保存完整历史缓存,而是像 RNN 一样把历史压进一个固定大小的状态里?</p><hr><h2 id="二、核心直觉-receptance-weighted-key-value" tabindex="-1">二、核心直觉:Receptance + Weighted Key Value <a class="header-anchor" href="#二、核心直觉-receptance-weighted-key-value" aria-label="Permalink to &quot;二、核心直觉:Receptance + Weighted Key Value&quot;">​</a></h2><p>RWKV 通常解释为 <strong>Receptance Weighted Key Value</strong>。名字里的三个关键词可以粗略理解为:</p><ul><li><strong>Key</strong>:当前输入产生的内容特征</li><li><strong>Value</strong>:真正要被累计和传递的信息</li><li><strong>Receptance</strong>:一个门控信号,决定当前时刻应该接收多少信息</li></ul><p>Transformer 用 attention 显式比较当前位置和历史所有位置;RWKV 则把历史信息递归地压缩进状态。每来一个新 token,模型根据当前 token 和已有状态更新下一步状态,并产生输出。</p><p>直觉上:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Transformer: 当前 token -&gt; 看历史所有 token -&gt; 得到输出</span></span>
<span class="line"><span>RWKV:        当前 token + 历史状态 -&gt; 更新状态 -&gt; 得到输出</span></span></code></pre></div><p>这让 RWKV 在生成时不需要随 token 数线性增长的 KV Cache。</p><hr><h2 id="三、它和-transformer-的关键差异" tabindex="-1">三、它和 Transformer 的关键差异 <a class="header-anchor" href="#三、它和-transformer-的关键差异" aria-label="Permalink to &quot;三、它和 Transformer 的关键差异&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Transformer</th><th>RWKV</th></tr></thead><tbody><tr><td>核心机制</td><td>Self-Attention</td><td>时间递归状态 + 加权 Key/Value</td></tr><tr><td>训练</td><td>高度并行</td><td>也可并行训练</td></tr><tr><td>推理</td><td>需要逐 token 生成,并维护 KV Cache</td><td>逐 token 生成,维护固定大小状态</td></tr><tr><td>长上下文显存</td><td>KV Cache 随上下文长度增长</td><td>状态大小基本固定</td></tr><tr><td>生态成熟度</td><td>极高</td><td>相对小众</td></tr><tr><td>工具链支持</td><td>vLLM、TensorRT-LLM、llama.cpp 等支持成熟</td><td>支持较少,需要看具体实现</td></tr></tbody></table><p>这里最重要的不是「谁绝对更好」,而是它们的成本结构不同。Transformer 把历史显式留在 KV Cache 里;RWKV 把历史折叠进 recurrent state 里。这会降低推理内存压力,但也意味着模型必须学会怎样把有用历史压进有限状态。</p><hr><h2 id="四、rwkv-的优势" tabindex="-1">四、RWKV 的优势 <a class="header-anchor" href="#四、rwkv-的优势" aria-label="Permalink to &quot;四、RWKV 的优势&quot;">​</a></h2><h3 id="_1-推理内存更稳定" tabindex="-1">1. 推理内存更稳定 <a class="header-anchor" href="#_1-推理内存更稳定" aria-label="Permalink to &quot;1. 推理内存更稳定&quot;">​</a></h3><p>RWKV 生成时维护固定大小状态,不会像 Transformer 那样因为上下文变长而让 KV Cache 线性增长。这对低显存设备和长文本应用很有吸引力。</p><h3 id="_2-适合流式处理" tabindex="-1">2. 适合流式处理 <a class="header-anchor" href="#_2-适合流式处理" aria-label="Permalink to &quot;2. 适合流式处理&quot;">​</a></h3><p>因为它天然是递归状态更新,所以很适合流式输入:新 token 来了就更新状态,不需要反复处理完整历史。</p><h3 id="_3-训练仍然可以并行" tabindex="-1">3. 训练仍然可以并行 <a class="header-anchor" href="#_3-训练仍然可以并行" aria-label="Permalink to &quot;3. 训练仍然可以并行&quot;">​</a></h3><p>传统 RNN 的一个大问题是训练难以充分并行。RWKV 的设计目标之一就是保留类似 Transformer 的并行训练路径,避免完全退回老式 RNN 的训练瓶颈。</p><h3 id="_4-部署形态更轻" tabindex="-1">4. 部署形态更轻 <a class="header-anchor" href="#_4-部署形态更轻" aria-label="Permalink to &quot;4. 部署形态更轻&quot;">​</a></h3><p>在边缘设备、本地应用、长会话机器人、低成本推理服务里,固定状态模型有实际工程价值。</p><hr><h2 id="五、rwkv-的局限" tabindex="-1">五、RWKV 的局限 <a class="header-anchor" href="#五、rwkv-的局限" aria-label="Permalink to &quot;五、RWKV 的局限&quot;">​</a></h2><h3 id="_1-生态不如-transformer" tabindex="-1">1. 生态不如 Transformer <a class="header-anchor" href="#_1-生态不如-transformer" aria-label="Permalink to &quot;1. 生态不如 Transformer&quot;">​</a></h3><p>主流推理框架、量化工具、微调方案、模型服务生态都优先围绕 Transformer 架构发展。RWKV 能用,但可选工具和社区经验明显少一些。</p><h3 id="_2-有限状态会带来信息压缩压力" tabindex="-1">2. 有限状态会带来信息压缩压力 <a class="header-anchor" href="#_2-有限状态会带来信息压缩压力" aria-label="Permalink to &quot;2. 有限状态会带来信息压缩压力&quot;">​</a></h3><p>Transformer 的 KV Cache 相当于把历史显式保留下来;RWKV 则要把历史压进状态。状态是有限的,模型必须决定什么该保留、什么可以遗忘。这是优势,也是风险。</p><h3 id="_3-同规模效果要看具体版本和训练数据" tabindex="-1">3. 同规模效果要看具体版本和训练数据 <a class="header-anchor" href="#_3-同规模效果要看具体版本和训练数据" aria-label="Permalink to &quot;3. 同规模效果要看具体版本和训练数据&quot;">​</a></h3><p>不能只看架构判断能力。模型效果取决于参数量、数据质量、训练配方、对齐方式、推理实现等一整套因素。同样参数规模下,RWKV 是否优于 Transformer 不能一概而论。</p><h3 id="_4-长上下文不是自动等于强记忆" tabindex="-1">4. 长上下文不是自动等于强记忆 <a class="header-anchor" href="#_4-长上下文不是自动等于强记忆" aria-label="Permalink to &quot;4. 长上下文不是自动等于强记忆&quot;">​</a></h3><p>RWKV 的固定状态让它在工程上更容易跑长序列,但这不等于它一定能完美记住任意早期细节。长期依赖能力仍然要靠训练和架构设计支撑。</p><hr><h2 id="六、版本演进" tabindex="-1">六、版本演进 <a class="header-anchor" href="#六、版本演进" aria-label="Permalink to &quot;六、版本演进&quot;">​</a></h2><p>RWKV 不是单一模型,而是一系列持续演进的架构和模型族。常见版本包括:</p><ul><li><strong>RWKV-4</strong>:较早被广泛认识的版本,奠定了 RWKV 的基本范式。</li><li><strong>RWKV-5 Eagle</strong>:继续改进时间混合和通道混合设计。</li><li><strong>RWKV-6 Finch</strong>:进一步增强动态状态表达。</li><li><strong>RWKV-7 Goose</strong>:继续沿着「更强的状态表达 + 常量级推理复杂度」方向演进。</li></ul><p>版本名里的 Eagle、Finch、Goose 是 RWKV 社区常见的代号。实际使用时要看具体 checkpoint、训练语料、上下文设定和推理后端,不要只看版本名。</p><hr><h2 id="七、适合关注-rwkv-的场景" tabindex="-1">七、适合关注 RWKV 的场景 <a class="header-anchor" href="#七、适合关注-rwkv-的场景" aria-label="Permalink to &quot;七、适合关注 RWKV 的场景&quot;">​</a></h2><p>如果你的目标是下面几类,RWKV 值得了解:</p><ol><li><strong>低显存本地推理</strong>:想在普通消费级设备上跑语言模型。</li><li><strong>长会话机器人</strong>:希望对话历史增长时推理状态不要线性膨胀。</li><li><strong>流式文本处理</strong>:输入持续到来,模型持续更新状态。</li><li><strong>边缘设备部署</strong>:需要固定内存占用和较低运行成本。</li><li><strong>研究 Transformer 替代路线</strong>:关注线性复杂度模型、RNN 复兴、状态空间模型等方向。</li></ol><p>如果你只是要最快接入通用 LLM 能力,目前大多数情况下 Transformer 系模型仍然更省心,比如 Llama、Qwen、Mistral、DeepSeek 等生态更成熟。</p><hr><h2 id="八、和其他非-transformer-路线的关系" tabindex="-1">八、和其他非 Transformer 路线的关系 <a class="header-anchor" href="#八、和其他非-transformer-路线的关系" aria-label="Permalink to &quot;八、和其他非 Transformer 路线的关系&quot;">​</a></h2><p>RWKV 可以放在「降低 attention 成本」的大方向里看。这个方向还包括:</p><ul><li><strong>线性注意力模型</strong>:把 attention 从二次复杂度降到线性复杂度。</li><li><strong>状态空间模型</strong>:例如 S4、Mamba 一类,用连续或离散状态建模序列。</li><li><strong>混合架构</strong>:部分层用 attention,部分层用 recurrent / state-space 机制。</li></ul><p>这些路线的共同目标是:减少标准 Transformer 在长序列上的计算和内存压力。但它们的设计哲学不同。RWKV 更像是把 LLM 重新写成可并行训练的 RNN 形态;Mamba 等状态空间模型则从另一套数学建模路径切入。</p><hr><h2 id="九、怎么判断是否该用-rwkv" tabindex="-1">九、怎么判断是否该用 RWKV <a class="header-anchor" href="#九、怎么判断是否该用-rwkv" aria-label="Permalink to &quot;九、怎么判断是否该用 RWKV&quot;">​</a></h2><p>可以用一个简单决策表:</p><table tabindex="0"><thead><tr><th>问题</th><th>如果答案是「是」</th></tr></thead><tbody><tr><td>你是否非常在意推理时 KV Cache 显存增长?</td><td>RWKV 值得评估</td></tr><tr><td>你是否需要成熟工具链和最大社区支持?</td><td>优先 Transformer</td></tr><tr><td>你是否在做架构研究或长序列实验?</td><td>RWKV 值得研究</td></tr><tr><td>你是否需要生产级高吞吐服务?</td><td>先确认推理后端和运维生态</td></tr><tr><td>你是否只是想调一个最强通用开源模型?</td><td>大概率先看 Qwen / Llama / DeepSeek / Mistral</td></tr></tbody></table><hr><h2 id="十、学习路线" tabindex="-1">十、学习路线 <a class="header-anchor" href="#十、学习路线" aria-label="Permalink to &quot;十、学习路线&quot;">​</a></h2><p>建议按这个顺序理解:</p><ol><li>先复习 <strong>RNN / LSTM</strong>:理解「状态」和「递归更新」。</li><li>再复习 <strong>Transformer / Attention / KV Cache</strong>:理解主流 LLM 的成本来自哪里。</li><li>然后看 <strong>RWKV 的 Time Mixing 和 Channel Mixing</strong>:理解它怎样替代 attention。</li><li>最后跑一个小模型:用官方 demo 或社区推理代码体验固定状态生成。</li></ol><p>真正理解 RWKV 的关键不是背公式,而是抓住这条主线:</p><blockquote><p>Transformer 把历史显式放在 KV Cache 里;RWKV 把历史压缩进 recurrent state 里。</p></blockquote><hr><h2 id="主要参考来源" tabindex="-1">主要参考来源 <a class="header-anchor" href="#主要参考来源" aria-label="Permalink to &quot;主要参考来源&quot;">​</a></h2><ul><li>RWKV 官方训练仓库: <a href="https://github.com/RWKV/RWKV-LM" target="_blank" rel="noreferrer">https://github.com/RWKV/RWKV-LM</a></li><li>RWKV Hugging Face 组织: <a href="https://huggingface.co/RWKV" target="_blank" rel="noreferrer">https://huggingface.co/RWKV</a></li><li>RWKV 论文: <em>RWKV: Reinventing RNNs for the Transformer Era</em></li><li>RWKV-7 Goose 论文: <em>RWKV-7 &quot;Goose&quot; with Expressive Dynamic State Evolution</em></li></ul>`,70)])])}const m=a(n,[["render",l]]);export{u as __pageData,m as default};
